var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"내가 봐야 할 사람은, 하나뿐이었다.","JPN":"私が見るべき人は、一人しかいなかった。","ENG":"I had only one person to look up to in my life.","TWN":"我該注視的人，就只有一位。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"COUNT_NPC_NULL_NULL","text":{"KOREA":"샬롯, 넌 무엇이냐?","JPN":"シャーロット、お前は何者だ？","ENG":"Carlota, what are you?","TWN":"夏洛特，你是誰？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"가문의…… 일부입니다.","JPN":"一族の……一部です。","ENG":"I am a part of the family.","TWN":"我是家族的……一部分。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COUNT_NPC_NULL_NULL","text":{"KOREA":"그렇다면 가문은 무엇이냐?","JPN":"ならば一族とは何だ？","ENG":"What is the family?","TWN":"那家族是什麼？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"저의 모든 것입니다.","JPN":"私のすべてです。","ENG":"My everything.","TWN":"是我的一切。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"COUNT_NPC_NULL_NULL","text":{"KOREA":"그렇다. 귀족이란 오직 가문을 위해 살고, 가문을 위해 죽어야 한다.","JPN":"そうだ。貴族とは一族のために生き、一族のために死ななければならない。","ENG":"Yes. A noble should live for the family, and die for the family.","TWN":"很好，所謂的貴族，就是生是為家族而生，死也是為家族而死。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COUNT_NPC_NULL_NULL","text":{"KOREA":"가문이 없으면 너는 아무것도 아니다.","JPN":"一族が無ければ、お前は何者でもない。","ENG":"You’re nothing without the family.","TWN":"沒有家族的話你什麼也不是。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COUNT_NPC_NULL_NULL","text":{"KOREA":"살아있는 동안은 물론 죽어서라도, 의식의 한 조각이나마 남아 있다면……","JPN":"生きている間はもちろん、死んだとしても、意識が一欠片だけでも残っているのなら……","ENG":"While you live, or even after you’re dead if you can...","TWN":"在你活著的時候，甚至是死後，就算你僅存最後一絲意識……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COUNT_NPC_NULL_NULL","text":{"KOREA":"오직 가문을 위해 네 모든 것을 바쳐야 한다.","JPN":"一族のために、お前のすべてを捧げなければならない。","ENG":"Sacrifice everything you have for the family.","TWN":"也要為家族獻出你的全所有。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COUNT_NPC_NULL_NULL","text":{"KOREA":"이 아비 앞에서 맹세해라.","JPN":"この父の前で誓え。","ENG":"Swear it in front of me.","TWN":"我要你在爸爸的面前發誓。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……맹세하겠습니다, 아버지.","JPN":"……誓います、お父様。","ENG":"I swear it, father.","TWN":"……我發誓。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EXECUTE_NPC_NULL_NULL","text":{"KOREA":"시간이 되었다, 백작! 아니, 반역자!","JPN":"時間だ、伯爵！　いや、反逆者！","ENG":"It’s your time, Count! No, traitor!","TWN":"伯爵…不對，逆賊！時候到了！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXECUTE_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"COUNT_NPC_NULL_NULL","text":{"KOREA":"샬롯! 네가 가문을 되살려야 한다! 알겠느냐!","JPN":"シャーロット！　お前がマルチネス家を再建するのだ！　わかったか！","ENG":"Carlota! You have to restore our family! Do not forget!","TWN":"夏洛特！你一定要復興家族！知道嗎！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXECUTE_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"EXECUTE_NPC_NULL_NULL","text":{"KOREA":"시끄러워! 당장 끌어내라!","JPN":"うるさい！　今すぐ引きずり出せ！","ENG":"Shut up! Get him out now!","TWN":"吵死了！立刻帶走！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXECUTE_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"COUNT_NPC_NULL_NULL","text":{"KOREA":"샬롯! 절대 잊지 마라! 넌 오로지 가문을 위해……!!","JPN":"シャーロット！　決して忘れるな！　お前は何があろうと一族のために……！！","ENG":"Carlota! Do not forget! Your family is everything you have!","TWN":"夏洛特！千萬要記住！你是為家族而……！！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"COUNT_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXECUTE_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_SMALL"},{"id":"L25_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이걸로 끝인가, 알렌 경?","JPN":"これで最後か、バーミンガム卿？","ENG":"Are we done now, Sir Allen?","TWN":"就這樣結束了嗎，艾倫愛卿？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그렇습니다, 전하.","JPN":"左様です、殿下。","ENG":"Yes, Your Highness.","TWN":"是的，殿下。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"마르티네즈 백작이라고 했나…….","JPN":"マルチネス伯爵と言ったか……","ENG":"Count Martinez, huh?","TWN":"他是馬汀尼茲伯爵嗎……"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"마왕이 준동하고 있는 이 때 2황자 편에 서서 반역을 일으키려 하다니.","JPN":"魔王が蠢動している今、第二皇子側について反逆を起こそうとするとは。","ENG":"Siding with the second prince to rebel against us, when the Demon Lord is breathing down on our neck?","TWN":"竟敢在魔王蠢蠢欲動的這個時候，幫著二皇子造反。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"참으로 한심한 작자로군.","JPN":"実に情けない者だ。","ENG":"Such stupidity.","TWN":"真是令人心寒的傢伙！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"반역의 대가로 뭘 받기로 했다고 했었지?","JPN":"反逆の代償として何を得ることになっていたのだ？","ENG":"What was he promised as a reward?","TWN":"他一定有收下什麼好處才會答應造反吧？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"마르티네즈 백작가는 이름만 귀족일 뿐, 이미 60년도 전에 영지와 재산을 잃고 몰락한 가문입니다.","JPN":"マルチネス伯爵家は名ばかりの貴族で、すでに60年も前に領地も財産も失い、没落した一族です。","ENG":"Count Martinez’s family already lost their fortune and land sixty years ago. They had nothing but their name.","TWN":"馬汀尼茲伯爵家只是名義上的貴族，他們家族早在60年前便已失去領地和財產。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"2황자가 황위에 오르면 과거의 영지와 재산을 돌려받는 것은 물론, 후작의 작위에 오를 예정이었다더군요.","JPN":"第二皇子が高位に就けば、過去の領地と財産を返すだけでなく、\\n侯爵の爵位につく予定だったそうです。","ENG":"The second prince promised him the title of marquis, along with his lost fortune and land, when the prince becomes king.","TWN":"若是二皇子順利登基，他們便能收回失去的領地和財產，還可受封侯爵。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그걸 위해 준비한 것이 저 소녀인가?","JPN":"そのために用意したのがあの少女か？","ENG":"So he prepared this girl for that?","TWN":"那個女孩就是他們計畫奪回失去地位和財富的方法？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그렇습니다.","JPN":"はい。","ENG":"Yes.","TWN":"沒錯。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"가문에 전해져 오는 마지막 보물인 마검 사파이어 프리즌…….","JPN":"一族に伝わる最後の宝、魔剣サファイアプリズン……","ENG":"The only treasure left in their family... Sapphire Prison, the Evil Sword.","TWN":"家族有留下最後一件寶物，就是魔劍 藍寶稜鏡……"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그것을 이용해 갓 태어났을 때부터 마법적, 주술적 의식으로 이상적인 검사를 만들었다고 합니다.","JPN":"それを利用して、生まれて間も無く魔法や呪術の儀式を行い、\\n理想の剣士を作り上げたそうです。","ENG":"They've used the sword along with other magical rituals since she was born to make her the perfect swordswoman.","TWN":"他們利用那把劍，在女孩一出生時，就用各種魔法和咒術儀式，想要把她打造成理想中的劍士。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"지속적인 세뇌와 의식의 부작용 탓에 감정은 거의 고갈되었으나, 실력만큼은 제국 기사단을 아득히 상회하는 수준입니다.","JPN":"繰り返した洗脳と意識の副作用のせいで感情はほとんど無くなりましたが、\\n実力だけは帝国騎士団をはるかに上回ります。","ENG":"She lost most of her emotions due to the constant brainwashing and magical rituals, but she certainly is the best fighter; far better than the Knights of the Empire.","TWN":"由於持續性的洗腦和儀式產生的副作用，導致她的感知力幾乎失能，但實力確實遠遠超出帝國騎士團。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그 힘으로 날 제거해서 반역의 중심에 서려고 했다는 말이군.","JPN":"その力で私を粛清して、反逆の中心に立とうとしたということか。","ENG":"So they planned to kill me using her, and become the main force in the rebellion.","TWN":"他們是想利用那股力量除掉我造反是吧？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"참으로 한심하지만…… 너무나 귀족적이지 않느냐?","JPN":"実に情けない……だが、あまりにも貴族的だと思わないか？","ENG":"That’s so pathetic... yet very noble.","TWN":"雖然令人心寒……但不覺得完全像是貴族作風嗎？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그 어리석음도, 허망함도.","JPN":"その愚かさも、虚しさも。","ENG":"All this stupidity and futility.","TWN":"那麼的愚蠢，那麼的不切實際！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"송구스럽습니다. 전하.","JPN":"恐縮です、殿下。","ENG":"Yes, Your Highness.","TWN":"殿下請息怒。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그럼 이 아이는 어떻게 하지?","JPN":"さて、この子はどうするんだ？","ENG":"So what shall I do with this child?","TWN":"那你打算拿她怎麼辦？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"국법대로라면……. 반역자의 자식 역시 반역자로 취급합니다.","JPN":"国法どおりなら……反逆者の子息も反逆者として扱います。","ENG":"According to the law... a child of a traitor is also a traitor.","TWN":"根據國法……逆賊之子與之同罪。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L2_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"아니. 그래서는 재미가 없지.","JPN":"いや、それでは面白くない。","ENG":"No, that’s no fun.","TWN":"不，這樣太無趣了。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"전하……?","JPN":"殿下……？","ENG":"Your Highness?","TWN":"殿下的意思是……？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"샬롯이라고 했나?","JPN":"シャーロットと言ったか？","ENG":"Carlota, isn’t it?","TWN":"你叫夏洛特？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"너는 반역자로서 죽어야 할 몸이지만 내게 충성할 기회를 주겠다.","JPN":"貴様は反逆者の身として死ななければならないが、\\n私に忠誠を誓う機会を与えよう。","ENG":"You deserve to die as a traitor, but I will give you a chance to serve me.","TWN":"你身為逆賊之子，本是戴罪之身，當以死謝罪，但我現在要給你一個效忠的機會。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"충성……?","JPN":"忠誠……？","ENG":"Serve you?","TWN":"效忠……？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그러면…… 가문을 다시 일으킬 수 있나요?","JPN":"そうすれば……一族を建て直すことができるのでしょうか？","ENG":"Will that help to clear my family’s name?","TWN":"這樣……就可以復興家族嗎？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"물론. 그것이 네 진정한 소망이라면, 네 충성의 대가로 이루게 해 주겠다.","JPN":"無論だ。それが貴様の本当の望みならば、\\n貴様の忠誠の見返りとして叶えてやろう。","ENG":"Of course. If that’s what you truly wish, I will grant it, if you serve me right.","TWN":"當然，若這是你真正的心願，只要你對我效忠，我自然會達成你的心願。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그것이 군주인 나의 의무이니까.","JPN":"それが君主である私の義務だからな。","ENG":"That is my duty as your ruler.","TWN":"這是身為君王的義務。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"그렇다면…….","JPN":"それなら……","ENG":"Then...","TWN":"那麼……"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"당신을 따르겠습니다, 전하.","JPN":"貴方に忠誠を誓います、殿下。","ENG":"I will serve you, Your Highness.","TWN":"我願意效忠於殿下。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"좋아! 이 시간부로 샬롯 마르티네즈를 구원기사단에 배속하겠다!","JPN":"よかろう。現時刻をもってシャーロット・マルチネスを救世騎士団に配属する！","ENG":"Very well. From now on, Carlota Martinez is one of the Knights of Redemption!","TWN":"很好！立刻將夏洛特 馬汀尼茲編入救贖騎士團！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"전하! 아무리 전하라도 반역자의 딸을 구원기사단에 배속하는 것은 폐하에 대한 도전으로 비춰질 수 있습니다!","JPN":"殿下！　いくら殿下とはいえ、反逆者の娘を\\n救世騎士団に配属することは、陛下への挑発とみなされる恐れがあります！","ENG":"Your Highness! The emperor will be displeased if you assign this traitor’s daughter to the Knights of Redemption, even if you are the crown prince!","TWN":"殿下！殿下若是將逆賊之女編入救贖騎士團，此舉恐怕會遭人解讀為在挑戰陛下！"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"흥, 방금 그 입으로 제국 기사단을 상회하는 실력자라고 말하지 않았던가?","JPN":"ふん、さきほどその口で帝国騎士団を上回る実力者だと言わなかったか？","ENG":"Hah, you said she was far better than the Knights of the Empire.","TWN":"哼，剛才不是你說她的實力遠遠超出帝國騎士團嗎？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그런 인재를 쉽게 버릴 수는 없는 법이지.","JPN":"そんな人材を簡単に捨ておくわけにはいかぬ。","ENG":"I won’t let such a useful resource go to waste.","TWN":"那當然不能放過這麼好的人才囉？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"구원기사단은 신분도 출신도 보지 않는다. 오직 실력만이 중요하지.","JPN":"救世騎士団では身分も出身も関係ない。実力だけを評価する。","ENG":"The Knights of Redemption don’t care about where they come from. They only care about their swordsmanship.","TWN":"救贖騎士團不論身分和出身，只論實力。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"ですが……","ENG":"But...","TWN":"可是……"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"음. 대신 그대의 먼 친척이라는 그 평민 소년도 구원기사단 입단 시험을 볼 수 있도록 허락하지.","JPN":"ふむ。その代わり、貴様の遠い親戚だというあの平民の子も\\n救世騎士団の入団試験を受けることを許可する。","ENG":"In exchange, I will allow your peasant cousin to take the Knights of Redemption entry test.","TWN":"嗯，這樣吧，你那個平民遠房親戚，我也允許他報考救贖騎士團。"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"어떤가, 알렌 경?","JPN":"それでどうだ、バーミンガム卿？","ENG":"What do you say, Sir Allen?","TWN":"這樣如何，艾倫愛卿？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"대체…… 왜 간단히 끝날 일을 복잡하게 만드시는 겁니까?","JPN":"いったいなぜ……簡単に済む話をわざわざ複雑にするのですか？","ENG":"Why... why do you make things complicated, Your Highness?","TWN":"殿下……事情明明可以很簡單就結束，為什麼要弄得如此複雜？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"경은 궁금하지 않나?","JPN":"卿は気にならないか？","ENG":"Aren’t you curious too?","TWN":"愛卿你不好奇嗎？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"저 소녀가 가문의 저주로부터 벗어나 진정 자신이 원하는 것이 무엇인지 깨달을 수 있을지 말이다.","JPN":"あの娘が一族の呪いから解き放たれ、\\n本当に自分が望むものに気づくことができるかどうか。","ENG":"I want to see if the girl will someday break out from the curse of her family and realize what she truly wants for herself.","TWN":"她能否脫離家族的詛咒，發現自己真正想要的是什麼？"},"stage":{"bg":"CASTLE_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"강해! 이건 아무래도……!","JPN":"強い！　これはさすがに……！","ENG":"She is strong! She must be...","TWN":"好厲害！恐怕……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서 퀸, 아니, 근접전에서는 지난번에 싸웠던 성녀님 이상이군요.","JPN":"リプレイサー・クイーン、\\nいえ、近接戦ではこの前戦った聖女様以上ですね。","ENG":"Stronger than the Replacer Queen, or even the Saintess when it comes to melee combat.","TWN":"比克隆·女皇，不，是比上次交手過的聖女還強！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아직 멀었나? 재촉하고 싶진 않지만 뭔가 이상해!","JPN":"まだか！？　急かしたくはないが、何かがおかしい！","ENG":"I don’t want to rush you, but you have to hurry! Something is happening!","TWN":"還很遠嗎？我也不想催促，但是好像哪裡怪怪的！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L34_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"계측기에 따르면 차원에 균열이 가고 있어.","JPN":"計測器によると、次元に亀裂が入っているようだ。","ENG":"According to the readings, the dimension is breaking up.","TWN":"根據測量器顯示，次元正在產生裂縫。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"정말로 뭔가가…… 다가오고 있는 건가?","JPN":"本当に何かが……近づいているのか？","ENG":"I think something is... actually coming this way.","TWN":"真的……有東西在接近嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"서둘러! 어서 등대를 파괴해야 해!","JPN":"急げ！　早く灯台を壊さないと！","ENG":"Hurry! We have to destroy the Lighthouse!","TWN":"動作快！快點毀掉燈塔！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};